var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"젠장! 여기도 함정이야!","JPN":"ちくしょう！　こっちも罠だ！","ENG":"Darn it, it’s another trap!","TWN":"可惡！這裡也是陷阱！"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"쿨럭, 쿨럭! 이 최루탄, 방독면을 써도 소용없어!","JPN":"ゴホッ、ゴホッ！　この催涙弾、防毒マスクを使ってもダメだ！","ENG":"*Cough, cough* The gas mask is no use against this tear bomb!","TWN":"咳咳！咳咳！是催淚彈！戴上防毒面罩也沒有用！"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"낙석이다! 이대로는 중장비가 움직이지 못해!","JPN":"落石だ！　このままでは重機を動かせない！","ENG":"A rockslide! We can’t move the heavy machinery!","TWN":"有落石！這樣怪手沒辦法動！"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":null,"text":{"KOREA":"계속 떨어진다! 다들 피해!","JPN":"また落ちてくるぞ！　避けろ！","ENG":"It keeps coming! Everyone, hide!","TWN":"　　"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"PMC_SUMMER_NULL_L","text":{"KOREA":"빌어먹을, 하루만에 숲을 요새로 만들어 놓다니…….","JPN":"くそ、たった一日で森を要塞化するとは……","ENG":"They turned the forest into a fortress overnight...","TWN":"該死的，竟然一天之內就設下這麼多陷阱……"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"PMC_SUMMER_NULL_L","text":{"KOREA":"휘둘리지 마! 적은 한 명뿐이다! 동요하지 말고 대열을 유지해!","JPN":"惑わされるな！　敵は一人だけだ！　動揺せず、隊列を維持しろ！","ENG":"Gather yourselves! It’s just one person! Keep calm and stay in formation!","TWN":"大家穩住！敵人只有一個人！別慌，隊伍不要亂掉！"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"PMC_SUMMER_NULL_NULL","text":{"KOREA":"대장님! 후미에 연막탄이 떨어졌습니다!","JPN":"隊長！　後方に煙幕弾が落とされました！","ENG":"Leader, they dropped a smoke bomb behind us!","TWN":"隊長！煙霧彈落在尾部了!"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PMC_SUMMER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L15_1","type":"dialog","speaker":"PMC_SUMMER_NULL_NULL","text":{"KOREA":"아니, 이건 연막탄이 아니라…… 졸음이…….","JPN":"いや、これは煙幕弾じゃなくて……眠気が……","ENG":"No, this is not a smoke bomb... I feel sleepy...","TWN":"不，這不是煙霧彈… 好睏…"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PMC_SUMMER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"PMC_SUMMER_NULL_L","text":{"KOREA":"큭……. 카운터답지 않은 수작을 부리는군.","JPN":"くっ……カウンターらしくない小細工を……","ENG":"Darn... I didn’t expect a Counter to use this sort of trick.","TWN":"咳……身為制裁者竟然還耍這些花招！"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"PMC_SUMMER_NULL_L","text":{"KOREA":"중장비는 내버려 둬! 건질 수 있는 것만 건져야 한다!","JPN":"重機は放っておけ！　持っていける装備だけ確保しろ！","ENG":"Leave the heavy machinery! We’ll just take what we can!","TWN":"怪手就扔著吧！其他能帶走多少算多少！"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"PMC_SUMMER_NULL_L","text":{"KOREA":"전속력으로 숲을 벗어나라! 엄폐물이 있는 장소에서는 우리가 불리해!","JPN":"全力で森を抜けろ！　掩ぺい物がある場所では俺たちが不利だ！","ENG":"Get out of the forest! We have move to an open space!","TWN":"立刻從森林裡撤退！在有遮蔽物的地方對我們不利！"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"PMC_SUMMER_NULL_L","text":{"KOREA":"드라코! 응답해! 오늘도 농땡이 피울 생각은 아니겠지?!","JPN":"ドラコ！　応答せよ！　まさか今日もサボるんじゃないだろうな！？","ENG":"Dracasia, respond! Are you goofing off again?","TWN":"德拉克，你在哪！該不會又再摸魚吧？"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"누구더러 농땡이래? 그 나이 먹고 나한테 매달리는 게 쪽팔리지도 않아?","JPN":"サボるだなんて失礼だな！　いい年したおっさんのくせに、あたしに頼るなんてみっともねえ。","ENG":"Don’t call me a goof-off. Aren’t you embarrassed to ask a young girl for help?","TWN":"誰摸魚啦？年紀一大把，還倚賴一個小孩子你不害羞嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L24_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"귀찮게 구는 빨강머리가 붙어 있어. 처리한 다음에 다시 연락해.","JPN":"手を焼かせる赤毛につけられてんの。処理した後連絡する。","ENG":"I have a redhead on me to take care of. Let’s talk later when I’m done.","TWN":"有一個紅頭髮的人在糾纏我，處理完再跟你聯絡啦！"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"SPEAR_FLORA_SUMMER_NULL","text":{"KOREA":"미안한데 처리한다고 하지 말아 줄래? 그 말 들으면 주방에 있을 때 생각나거든?","JPN":"悪いけど、処理という言葉は使わないでくれる？　厨房にいる気持ちになるのよね。","ENG":"Don’t say the word “done”, please. That expression reminds me of my kitchen days.","TWN":"不好意思，可以不要說處理嗎？ 聽到處理我就會想到以前在廚房的時候。"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_HIT_METAL"},{"id":"L30_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"캬핫, 뭐래? 듣기 싫으면 귀찮게 굴지 말고 비키시지?","JPN":"あ？　何ほざいてるわけ？　聞きたくないなら、邪魔しないでどけよ！","ENG":"Hah, what? If you don’t like the way I talk, just leave.","TWN":"蛤？在說什麼？不想聽就滾開，別纏著我！"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"그 실력으로 내 앞에서 뻗대기엔 죽었다 깨어나도 모자라거든?","JPN":"その実力じゃ、あたしの足元にも及ばねえ！","ENG":"You’ll never beat me with that skill.","TWN":"憑你那三腳貓的功夫，還敢在我面前炫技？還差得遠咧！"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SPEAR_FLORA_SUMMER_NULL","text":{"KOREA":"흥. 내 실력이 부족한 건 나도 잘 알아. 마크 그 인간만 아니었어도 프린터기나 붙잡고 있었을 테니까.","JPN":"ふん。私の実力が足りないのは自分でも知ってる。マークのやつがいなかったら、今頃雑務ばかり任されていたはずだから。","ENG":"Well, I know I’m not strong enough. I would have been in the office printing handouts if it wasn’t for Mark.","TWN":"哼。我很清楚自己有幾兩重，若不是因為馬克，我可能現在還只能是個印表機小妹。"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SPEAR_FLORA_SUMMER_NULL","text":{"KOREA":"그래도 한식구인 애가 휴가 날에 울상 짓는 꼴은 보기 싫다고!","JPN":"でも、家族同然の子がせっかく帰省したのに、泣きそうな顔をするのは見たくないの！","ENG":"But still, I don’t want to see my colleague getting all teary while she’s on vacation!","TWN":"但我不樂意見到人家的孩子在休假時哭喪著臉！"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"GRANDFA_NPC_SUMMER_NULL","text":{"KOREA":"어이쿠……. 간 떨어질 뻔했네.","JPN":"おっと……びっくりしたのう。","ENG":"Whoops... That was loud.","TWN":"哎呀…好嚇人啊。"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"GRANDMA_NPC_SUMMER_NULL","text":{"KOREA":"저기 언덕에서 들렸나 봐요. 다들 괜찮으려나 몰라.","JPN":"あそこの丘からの音じゃな。みんな大丈夫かい。","ENG":"I think it was from that hill. I hope everyone’s okay.","TWN":"好像是從那個山坡上傳來的聲音，不知道大家怎麼樣了？"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_NULL","text":{"KOREA":"모네야, 네 친구 분들 정말 괜찮으시겠지?","JPN":"モネ、お友達の方々は本当に大丈夫なの？","ENG":"Mone, are you sure your friends will be alright?","TWN":"莫妮，你的朋友應該不會有事吧？"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_PRIDE"}}}},{"id":"L42_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"물론임다! 릴리 선배님도 리코리스 선배님도 엄청 강하심다!","JPN":"もちろんっす！　リリー先輩もリコリス先輩も、めちゃくちゃ強いっす！","ENG":"Of course! Lily and Lycoris are super strong, mama!","TWN":"當然囉！莉莉前輩和莉克麗絲前輩都很強唷！"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"우으……. 그치만 메이드장님만 계셨더라도 무지 마음 놓였을 텐데 말임다……..","JPN":"むう……でも、もしメイド長が居てくれたなら、もっと安心できるっすね……","ENG":"But... It would have been much better if the Chief Maid was here with us…","TWN":"嗚…不過如果是女僕長，就算只有她在也可以超級安心。"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L44_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L47_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"생각보다 상대도 필사적인가 보군요.","JPN":"思った以上に相手も必死ですね。","ENG":"They are fighting back pretty hard.","TWN":"看來對手比想象中拼命呢。"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"그 둘만으로는 오래 버티지 못하겠습니다. 맨션의 장기는 전면전이 아니라 암습이니까요.","JPN":"あの二人だけでは長く持ちません。マンションの得意分野は正面攻撃ではなく、奇襲ですから。","ENG":"I don’t think those two will last for long. The Mansion is specialized in surprise attacks rather than full-scale warfare.","TWN":"光靠他們兩個撐不了多久的，畢竟曼森的專長是突襲，而不是正面攻擊。"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"하하. 그래서 릴리 양에게 미리 얘기해 뒀다네. 무리해서 결판을 내려 하지는 않을 거야.","JPN":"ハハハ。だからリリーには先に話してある。無理して決着をつけることはしないはずだ。","ENG":"Hah hah, I told Lily about that already. They won’t exert themselves.","TWN":"哈哈。所以我有先對莉莉打預防針，她應該不會勉強行事。"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L50_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"혼자만 아는 소리를 하시는 걸 보니 또 저 몰래 무슨 수작을 부리셨군요.","JPN":"また自分だけが知っている話なんですね。こっそりと何を企んでいるのですか。","ENG":"I don’t understand. What kind of trickery did you use this time?","TWN":"又再說一些只有自己聽得懂的話，是不是又背著我耍什麼花招？"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L1_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"크흠. 수작이라니, 경험에서 우러나온 지혜라고 해 주게나.","JPN":"えっへん、企みだなんて。経験から生まれた知恵と言ってくれ。","ENG":"Hmpf, it’s not trickery. It’s more like wisdom of experience.","TWN":"哎呀～哪是什麼花招？是從經驗當中得到的智慧好嗎～"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L4_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"어라?","JPN":"あれ？","ENG":"Huh?","TWN":"嗯？"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L5_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"엄니! 저, 저기 누가 오고 있슴다!","JPN":"母ちゃん！　向こうから誰かが来るっす！","ENG":"Mama! S-someone is coming!","TWN":"媽媽，有…有人來了！"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"뭐야, 다들 나와서 기다리고 있었네?","JPN":"なんだ、みんな集まってお出迎えでもしてくれてんの？","ENG":"Hey, you were all waiting for me?","TWN":"哎呀～大家都出來迎接喔？"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL"},{"id":"L8_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"기대하던 얼굴이 아니라 어쩌나, 촌뜨기들?","JPN":"待ち人じゃなくて悪かったな。","ENG":"You didn’t expect to see me, hillbillies?","TWN":"但怎麼辦呢，土包子？我不是你們在等的人？"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};